```ts
import { Client } from "appwrite";

// 1) Init Appwrite client
const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const DATABASE_ID = "<DATABASE_ID>";
const TABLE_ID = "<TABLE_ID>";
const BUCKET_ID = "<BUCKET_ID>";

// 2) Subscribe to BOTH channels at once
const unsubscribe = client.subscribe(
  [
    `databases.${DATABASE_ID}.tables.${TABLE_ID}.rows`, // document/row changes
    `buckets.${BUCKET_ID}.files`,                       // file uploads/changes
  ],
  (event) => {
    const { events, payload, channels } = event;

    const isRowEvent = channels.some((c) =>
      c.startsWith(`databases.${DATABASE_ID}.tables.${TABLE_ID}.rows`)
    );

    const isFileEvent = channels.some((c) =>
      c.startsWith(`buckets.${BUCKET_ID}.files`)
    );

    // 3) Handle row (document) events
    if (isRowEvent) {
      if (events.some((e) => e.endsWith(".create"))) {
        console.log("🆕 Row created:", payload);
      } else if (events.some((e) => e.endsWith(".update"))) {
        console.log("✏️ Row updated:", payload);
      } else if (events.some((e) => e.endsWith(".delete"))) {
        console.log("🗑️ Row deleted:", payload);
      } else {
        console.log("📄 Row event:", events, payload);
      }
      return;
    }

    // 4) Handle file events (uploads are .create)
    if (isFileEvent) {
      if (events.some((e) => e.endsWith(".create"))) {
        console.log("📤 File uploaded:", payload);
      } else if (events.some((e) => e.endsWith(".update"))) {
        console.log("🧾 File metadata updated:", payload);
      } else if (events.some((e) => e.endsWith(".delete"))) {
        console.log("❌ File deleted:", payload);
      } else {
        console.log("📁 File event:", events, payload);
      }
    }
  }
);

// Later (cleanup): call unsubscribe()
// unsubscribe();
