# Email/Password Authentication with Appwrite Web SDK

## Installation

```bash
npm install appwrite
```

## Implementation

```javascript
import { Client, Account, ID } from 'appwrite';

// 1. Set up the Appwrite Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('<YOUR_PROJECT_ID>');             // Your Project ID

const account = new Account(client);

// 2. Sign Up - Create a new account
async function signup(email, password, name) {
    try {
        const user = await account.create(
            ID.unique(),  // userId - auto-generate unique ID
            email,        // email
            password,     // password (minimum 8 characters)
            name          // name (optional)
        );
        console.log('Account created successfully:', user);
        return user;
    } catch (error) {
        console.error('Signup failed:', error.message);
        throw error;
    }
}

// 3. Login - Create an email/password session
async function login(email, password) {
    try {
        const session = await account.createEmailPasswordSession(email, password);
        console.log('Logged in successfully:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error.message);
        throw error;
    }
}

// 4. Get the currently logged-in user
async function getCurrentUser() {
    try {
        const user = await account.get();
        console.log('Current user:', user);
        return user;
    } catch (error) {
        console.error('Not logged in:', error.message);
        return null;
    }
}

// 5. Logout - Delete the current session
async function logout() {
    try {
        await account.deleteSession('current');
        console.log('Logged out successfully');
    } catch (error) {
        console.error('Logout failed:', error.message);
        throw error;
    }
}

// --- Usage Example ---
async function main() {
    // Sign up a new user
    await signup('user@example.com', 'mypassword123', 'John Doe');

    // Log in with the new account (creates a session)
    await login('user@example.com', 'mypassword123');

    // Fetch the current user's details
    const user = await getCurrentUser();

    // Log out
    await logout();
}

main();
```

## Key Points

| Concept | Details |
|---|---|
| **`ID.unique()`** | Generates a unique ID for the new user. You can also pass a custom string ID. |
| **Password requirement** | Must be between 8 and 256 characters long. |
| **`createEmailPasswordSession`** | Creates a session cookie that authenticates subsequent requests. |
| **`deleteSession('current')`** | Destroys only the current session. Use `account.deleteSessions()` to revoke **all** sessions. |
| **Session persistence** | In browsers, the session is stored automatically as an `HttpOnly` cookie by Appwrite. |

> **Note:** Make sure your Appwrite project has the **Email/Password** auth method enabled under **Auth → Settings** in the Appwrite Console.

# Creating a Database, Collection, and Document with Appwrite Web SDK

Here's a complete example using the Appwrite Web SDK to set up a tasks collection and insert a document.

## 1. Setup & Initialize the Client

```javascript
import { Client, Databases, ID, Permission, Role } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('<YOUR_PROJECT_ID>');             // Your project ID

const databases = new Databases(client);
```

## 2. Create the Database

```javascript
async function createDatabase() {
    try {
        const database = await databases.create(
            ID.unique(),
            'TasksDB' // Database name
        );
        console.log('Database created:', database.$id);
        return database;
    } catch (error) {
        console.error('Error creating database:', error);
        throw error;
    }
}
```

## 3. Create the Collection and Attributes

```javascript
async function createCollection(databaseId) {
    try {
        // Create the collection
        const collection = await databases.createCollection(
            databaseId,
            ID.unique(),
            'tasks',
            [
                Permission.read(Role.any()),
                Permission.create(Role.users()),
                Permission.update(Role.users()),
                Permission.delete(Role.users())
            ]
        );
        console.log('Collection created:', collection.$id);

        // Create "title" string attribute
        await databases.createStringAttribute(
            databaseId,
            collection.$id,
            'title',       // key
            255,           // size (max length)
            true           // required
        );
        console.log('Attribute "title" created');

        // Create "completed" boolean attribute
        await databases.createBooleanAttribute(
            databaseId,
            collection.$id,
            'completed',   // key
            true,          // required
            false          // default value
        );
        console.log('Attribute "completed" created');

        // Create "dueDate" datetime attribute
        await databases.createDatetimeAttribute(
            databaseId,
            collection.$id,
            'dueDate',     // key
            false          // required
        );
        console.log('Attribute "dueDate" created');

        return collection;
    } catch (error) {
        console.error('Error creating collection/attributes:', error);
        throw error;
    }
}
```

## 4. Insert a Document

```javascript
async function createDocument(databaseId, collectionId) {
    try {
        const document = await databases.createDocument(
            databaseId,
            collectionId,
            ID.unique(),
            {
                title: 'Finish Appwrite tutorial',
                completed: false,
                dueDate: new Date('2025-03-15T10:00:00.000Z').toISOString()
            }
        );
        console.log('Document created:', document);
        return document;
    } catch (error) {
        console.error('Error creating document:', error);
        throw error;
    }
}
```

## 5. Run Everything Together

```javascript
async function main() {
    try {
        // Step 1: Create the database
        const database = await createDatabase();

        // Step 2: Create collection and attributes
        const collection = await createCollection(database.$id);

        // Step 3: Wait for attributes to be processed
        // Attributes are created asynchronously; a short delay ensures they're ready
        console.log('Waiting for attributes to be available...');
        await new Promise((resolve) => setTimeout(resolve, 2000));

        // Step 4: Insert a document
        const document = await createDocument(database.$id, collection.$id);

        console.log('Setup complete!');
        console.log(`Database ID: ${database.$id}`);
        console.log(`Collection ID: ${collection.$id}`);
        console.log(`Document ID: ${document.$id}`);
    } catch (error) {
        console.error('Setup failed:', error);
    }
}

main();
```

## Key Notes

- **Attribute processing delay**: Attributes are created asynchronously on the server. The `setTimeout` ensures they're available before inserting a document. In production, you should poll the collection's attributes and check their `status` equals `"available"`.
- **Permissions**: The example grants read access to anyone and write access to authenticated users. Adjust `Permission` and `Role` values based on your security requirements.
- **`ID.unique()`**: Generates a unique ID server-side for databases, collections, and documents. You can also pass your own custom string ID instead.
- **Creating databases and collections** typically requires an API key with server-side SDKs or an admin-scoped session. If running from a client app, these operations are usually done via the Appwrite Console or a server-side function.

# Appwrite Function: Personalized Greeting

Here's an Appwrite Function in Node.js that receives a JSON body with a "name" field and returns a personalized greeting:

```javascript
export default async ({ req, res, log, error }) => {
  // Handle the request
  if (req.method === 'POST') {
    try {
      // Parse the JSON body - Appwrite automatically parses JSON bodies
      const { name } = req.body;

      if (!name) {
        return res.json(
          { ok: false, message: 'Missing required field: "name"' },
          400
        );
      }

      log(`Greeting requested for: ${name}`);

      return res.json({
        ok: true,
        greeting: `Hello, ${name}! Welcome to Appwrite!`,
      });
    } catch (err) {
      error(`Error processing request: ${err.message}`);
      return res.json(
        { ok: false, message: 'Failed to process request' },
        500
      );
    }
  }

  // Handle non-POST requests
  return res.json(
    { ok: false, message: 'Method not allowed. Please use POST.' },
    405
  );
};
```

## Key Details

- **Function Signature**: The function uses the modern Appwrite Functions signature, exporting a default `async` function that destructures `{ req, res, log, error }` from the context object.
- **`req.body`**: Appwrite automatically parses JSON request bodies when the `Content-Type` header is `application/json`, so no manual `JSON.parse()` is needed.
- **`res.json(body, statusCode)`**: Returns a JSON response with the appropriate status code.
- **`log()` / `error()`**: Built-in logging utilities that write to the Appwrite function execution logs.

## Example Usage

**Request:**
```bash
curl -X POST https://<APPWRITE_ENDPOINT>/functions/<FUNCTION_ID>/executions \
  -H "Content-Type: application/json" \
  -H "X-Appwrite-Project: <PROJECT_ID>" \
  -d '{"name": "Alice"}'
```

**Response:**
```json
{
  "ok": true,
  "greeting": "Hello, Alice! Welcome to Appwrite!"
}
```

## Project Structure

```
my-function/
├── src/
│   └── main.js        # The function code above
└── package.json
```

**`package.json`:**
```json
{
  "name": "greeting-function",
  "version": "1.0.0",
  "type": "module",
  "main": "src/main.js"
}
```

> **Note**: The `"type": "module"` field is required to use ES module `export default` syntax, which is the standard for Appwrite Node.js functions.

# Appwrite Storage: Create Bucket, Upload File & Get Preview

## 1. Initialize the Client

```javascript
import { Client, Storage, ID, Permission, Role, InputFile } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<YOUR_PROJECT_ID>');

const storage = new Storage(client);
```

## 2. Create a Bucket (Server-Side with Node.js SDK)

> **Note:** Bucket creation requires an API key and is typically done server-side or via the Appwrite Console.

```javascript
import { Client, Storage, Permission, Role } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<YOUR_PROJECT_ID>')
    .setKey('<YOUR_API_KEY>');

const storage = new Storage(client);

async function createBucket() {
    try {
        const bucket = await storage.createBucket(
            ID.unique(),                // Bucket ID
            'Images',                   // Bucket name
            [
                Permission.read(Role.any()),           // Anyone can read/view
                Permission.create(Role.users()),       // Authenticated users can upload
                Permission.update(Role.users()),       // Authenticated users can update
                Permission.delete(Role.users()),       // Authenticated users can delete
            ],
            false,                      // fileSecurity (false = bucket-level permissions only)
            true,                       // enabled
            30000000,                   // maximumFileSize (30MB)
            ['image/png', 'image/jpeg', 'image/gif', 'image/webp'],  // allowedFileExtensions
            'gzip',                     // compression
            true,                       // encryption
            false                       // antivirus
        );

        console.log('Bucket created:', bucket);
        return bucket;
    } catch (error) {
        console.error('Error creating bucket:', error);
    }
}

createBucket();
```

## 3. Upload a File (Client-Side - Web SDK)

```javascript
const BUCKET_ID = '<YOUR_BUCKET_ID>';

async function uploadFile() {
    try {
        // Using a file input element from the DOM
        const fileInput = document.getElementById('fileUpload');
        const file = fileInput.files[0];

        const response = await storage.createFile(
            BUCKET_ID,
            ID.unique(),
            file,
            [
                Permission.read(Role.any()),              // Anyone can view
                Permission.update(Role.user('<USER_ID>')), // Only the owner can update
                Permission.delete(Role.user('<USER_ID>')), // Only the owner can delete
            ]
        );

        console.log('File uploaded:', response);
        return response;
    } catch (error) {
        console.error('Upload error:', error);
    }
}
```

> **Note:** File-level permissions only apply when `fileSecurity` is set to `true` on the bucket. Otherwise, bucket-level permissions are used.

## 4. Get a File Preview URL

```javascript
function getFilePreview(fileId) {
    const result = storage.getFilePreview(
        BUCKET_ID,
        fileId,
        400,        // width (px)
        300,        // height (px)
        'center',   // gravity (crop position)
        90,         // quality (1-100)
        0,          // borderWidth
        '',         // borderColor
        0,          // borderRadius
        1,          // opacity (0-1)
        0,          // rotation (-360 to 360)
        '',         // background color
        'webp'      // output format: jpg, png, gif, webp
    );

    console.log('Preview URL:', result.href);
    return result; // Returns a URL object
}
```

## 5. Full Working Example

```html
<!DOCTYPE html>
<html>
<body>
    <input type="file" id="fileUpload" accept="image/*" />
    <button onclick="handleUpload()">Upload</button>
    <img id="preview" />

    <script type="module">
        import { Client, Storage, ID, Permission, Role } from 'appwrite';

        const client = new Client()
            .setEndpoint('https://cloud.appwrite.io/v1')
            .setProject('<YOUR_PROJECT_ID>');

        const storage = new Storage(client);
        const BUCKET_ID = '<YOUR_BUCKET_ID>';

        window.handleUpload = async function () {
            const fileInput = document.getElementById('fileUpload');
            const file = fileInput.files[0];

            if (!file) {
                alert('Please select a file');
                return;
            }

            try {
                // Upload the file
                const uploadedFile = await storage.createFile(
                    BUCKET_ID,
                    ID.unique(),
                    file
                );

                console.log('Uploaded:', uploadedFile);

                // Get preview URL
                const previewUrl = storage.getFilePreview(
                    BUCKET_ID,
                    uploadedFile.$id,
                    400,    // width
                    400,    // height
                    'center',
                    80      // quality
                );

                // Display the preview
                document.getElementById('preview').src = previewUrl;
                console.log('Preview URL:', previewUrl.href);
            } catch (error) {
                console.error('Error:', error.message);
            }
        };
    </script>
</body>
</html>
```

## Key Points

| Concept | Details |
|---|---|
| **Bucket creation** | Server-side only (requires API key) |
| **`fileSecurity`** | Set to `true` to enable file-level permissions; `false` uses bucket-level only |
| **`getFilePreview`** | Returns a `URL` object, not a promise — no `await` needed |
| **Supported formats** | Preview works with images: JPEG, PNG, GIF, WebP |
| **Permission roles** | `Role.any()` (everyone), `Role.users()` (authenticated), `Role.user(id)` (specific user), `Role.guests()` (unauthenticated) |

# Push Notifications with Appwrite Messaging

## Supported Push Notification Providers

Appwrite Messaging supports the following push notification providers:

- **FCM (Firebase Cloud Messaging)** — for Android and web
- **APNS (Apple Push Notification Service)** — for iOS and macOS
- **Huawei Push Kit** — for Huawei devices

---

## Setup Steps

### 1. Configure a Push Notification Provider

First, add a provider in the Appwrite Console:

**For FCM:**
- Go to **Messaging → Providers → Add Provider → Push → FCM**
- Upload your Firebase service account JSON key file (obtained from Firebase Console → Project Settings → Service Accounts)

**For APNS:**
- Go to **Messaging → Providers → Add Provider → Push → APNS**
- Provide your **Bundle ID**, **Team ID**, **Key ID**, and upload your `.p8` authentication key file

**For Huawei Push Kit:**
- Provide your **Huawei App ID** and **App Secret**

### 2. Register Device Targets

On the client side, register devices to receive push notifications. Users' devices need to be registered as **targets**:

```javascript
import { Client, Messaging } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

// After obtaining the device's push token from FCM/APNS SDK:
const account = new Account(client);

// Create a push target for the logged-in user
await account.createPushTarget(
    '[TARGET_ID]',       // Unique target ID (or use ID.unique())
    deviceToken,         // FCM/APNS device token
    '[PROVIDER_ID]'      // Your Appwrite provider ID
);
```

### 3. Create a Topic

Topics allow you to group targets for broadcast messaging:

```javascript
import { Client, Messaging } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey('[API_KEY]');

const messaging = new Messaging(client);

// Create a topic
const topic = await messaging.createTopic(
    '[TOPIC_ID]',        // Unique topic ID (or use ID.unique())
    'announcements'      // Topic name
);
```

### 4. Subscribe Targets to a Topic

```javascript
await messaging.createSubscriber(
    '[TOPIC_ID]',        // Topic ID
    '[SUBSCRIBER_ID]',   // Unique subscriber ID
    '[TARGET_ID]'        // The target (device) to subscribe
);
```

### 5. Send a Push Notification to a Topic

```javascript
const message = await messaging.createPush(
    '[MESSAGE_ID]',          // Unique message ID (or use ID.unique())
    'New Update Available',  // Notification title
    'Check out the latest features!', // Notification body
    ['[TOPIC_ID]'],          // Array of topic IDs
    [],                      // Array of user IDs (optional)
    [],                      // Array of target IDs (optional)
    {                        // Additional optional parameters
        // data: { key: 'value' },  // Custom data payload
        // image: 'https://example.com/image.png',
        // sound: 'default',
        // badge: 1,
        // draft: false,
        // scheduledAt: '2024-01-01T00:00:00.000+00:00'
    }
);
```

---

## Key Concepts

| Concept | Description |
|---------|-------------|
| **Provider** | The push service (FCM, APNS, Huawei) configured in Appwrite |
| **Target** | A specific device registered to receive notifications |
| **Topic** | A group/channel that targets can subscribe to |
| **Subscriber** | A link between a target and a topic |

## Sending Options

You can send push notifications to:
- **Topics** — broadcast to all subscribers of a topic
- **Users** — send to all registered devices of specific users
- **Targets** — send directly to specific device targets

You can also **schedule** messages by setting the `scheduledAt` parameter, or save them as **drafts** for later sending.

Based on the documentation, here are the key `APPWRITE_FUNCTION_*` environment variables available inside an Appwrite Function at runtime:

---

### 1. `APPWRITE_FUNCTION_ID`
**What it's for:** Contains the unique ID of the currently executing function. This lets your function code identify *which* function it is, which is useful when you share handler logic across multiple functions or need to reference the function's own ID (e.g., for logging or self-invocation).

---

### 2. `APPWRITE_FUNCTION_PROJECT_ID`
**What it's for:** Holds the ID of the Appwrite project the function belongs to. This is essential for initializing the Appwrite server SDK client inside your function so it can interact with databases, storage, users, and other project resources. For example:

```typescript
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject(process.env.APPWRITE_FUNCTION_PROJECT_ID)
    .setKey(process.env.APPWRITE_FUNCTION_API_KEY);
```

---

### 3. `APPWRITE_FUNCTION_API_KEY`
**What it's for:** Provides a scoped API key that the function can use to authenticate with the Appwrite server SDK. This key is automatically provisioned by Appwrite and allows the function to perform server-side operations (like managing users, reading/writing database rows, or accessing storage) without you having to manually create and inject an API key.

---

### Bonus mentions:

- **`APPWRITE_FUNCTION_DEPLOYMENT`** — The ID of the current active deployment of the function.
- **`APPWRITE_FUNCTION_RUNTIME_NAME` / `APPWRITE_FUNCTION_RUNTIME_VERSION`** — The name and version of the runtime environment (e.g., `node`, `18.0`), useful for runtime-specific logic or diagnostics.

---

### How they're typically used together

Inside a function handler, these variables let you bootstrap a fully authenticated Appwrite client without hardcoding secrets:

```typescript
// Node.js function example
import { Client, TablesDB } from 'node-appwrite';

export default async ({ req, res, log }) => {
    const client = new Client()
        .setEndpoint(process.env.APPWRITE_FUNCTION_ENDPOINT)
        .setProject(process.env.APPWRITE_FUNCTION_PROJECT_ID)
        .setKey(process.env.APPWRITE_FUNCTION_API_KEY);

    const db = new TablesDB(client);
    // ... interact with your project's resources
};
```

This pattern ensures your function code is portable and doesn't contain hardcoded credentials.

Here's exactly how to subscribe to **both** a database collection's documents **and** a storage bucket's files in a single `client.subscribe()` call:

## Single Subscribe Call for Multiple Channels

```typescript
const unsubscribe = client.subscribe(
  [
    'databases.[DATABASE_ID].tables.[TABLE_ID].rows',
    'buckets.[BUCKET_ID].files'
  ],
  (response) => {
    console.log(response.events);   // e.g. ['databases.*.tables.*.rows.*.create']
    console.log(response.payload);  // the affected resource (document or file)
    console.log(response.channels); // which channel(s) matched
  }
);

// Later, to stop listening:
unsubscribe();
```

## The Exact Channel Strings

| Channel String | Listens To |
|---|---|
| `databases.[DATABASE_ID].tables.[TABLE_ID].rows` | All row (document) changes (create, update, delete) in the specified table |
| `buckets.[BUCKET_ID].files` | All file changes (create, update, delete) in the specified bucket |

Replace `[DATABASE_ID]`, `[TABLE_ID]`, and `[BUCKET_ID]` with your actual resource IDs.

## How to Tell Which Event Fired

Since both channels share one callback, use the `response` object to distinguish events:

```typescript
const unsubscribe = client.subscribe(
  [
    'databases.mydb.tables.todos.rows',
    'buckets.avatars.files'
  ],
  (response) => {
    if (response.events.some(e => e.includes('.rows.'))) {
      console.log('Document changed:', response.payload);
    }

    if (response.events.some(e => e.includes('.files.'))) {
      console.log('File changed:', response.payload);
    }
  }
);
```

### Key Points

- **Pass an array** of channel strings as the first argument to listen to multiple channels at once.
- The **`response` object** includes `events` (array of event strings like `databases.*.tables.*.rows.*.create`), `payload` (the affected resource), `channels` (which subscribed channels matched), and `timestamp`.
- You can also subscribe to a **specific document** or **specific file** by appending its ID: `databases.[DB_ID].tables.[TABLE_ID].rows.[ROW_ID]` or `buckets.[BUCKET_ID].files.[FILE_ID]`.

```typescript
import { Client, TablesDB, Storage, ID, Query } from 'appwrite';

// Initialize the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);
const storage = new Storage(client);

// Subscribe to both row changes and file uploads simultaneously
const unsubscribe = client.subscribe(
    [
        'databases.[DATABASE_ID].tables.[TABLE_ID].rows',
        'buckets.[BUCKET_ID].files',
    ],
    (response) => {
        const { events, payload, channels, timestamp } = response;

        // Handle row (document) events
        if (events.some((e) => e.includes('.rows.'))) {
            if (events.some((e) => e.endsWith('.create'))) {
                console.log('Row created:', payload.$id);
                handleRowCreated(payload);
            } else if (events.some((e) => e.endsWith('.update'))) {
                console.log('Row updated:', payload.$id);
                handleRowUpdated(payload);
            } else if (events.some((e) => e.endsWith('.delete'))) {
                console.log('Row deleted:', payload.$id);
                handleRowDeleted(payload);
            }
        }

        // Handle file events
        if (events.some((e) => e.includes('.files.'))) {
            if (events.some((e) => e.endsWith('.create'))) {
                console.log('File uploaded:', payload.$id, payload.name);
                handleFileUploaded(payload);
            } else if (events.some((e) => e.endsWith('.update'))) {
                console.log('File updated:', payload.$id);
                handleFileUpdated(payload);
            } else if (events.some((e) => e.endsWith('.delete'))) {
                console.log('File deleted:', payload.$id);
                handleFileDeleted(payload);
            }
        }

        console.log(`Event at ${timestamp} on channels:`, channels);
    }
);

// --- Row event handlers ---

function handleRowCreated(row: Record<string, any>) {
    // e.g., append to a list in the UI
    const listEl = document.getElementById('row-list');
    if (listEl) {
        const item = document.createElement('li');
        item.id = `row-${row.$id}`;
        item.textContent = row.title ?? row.$id;
        listEl.appendChild(item);
    }
}

function handleRowUpdated(row: Record<string, any>) {
    // e.g., update the existing item in the UI
    const item = document.getElementById(`row-${row.$id}`);
    if (item) {
        item.textContent = row.title ?? row.$id;
    }
}

function handleRowDeleted(row: Record<string, any>) {
    // e.g., remove the item from the UI
    const item = document.getElementById(`row-${row.$id}`);
    if (item) {
        item.remove();
    }
}

// --- File event handlers ---

function handleFileUploaded(file: Record<string, any>) {
    // e.g., show a preview of the uploaded file
    const gallery = document.getElementById('file-gallery');
    if (gallery) {
        const preview = document.createElement('div');
        preview.id = `file-${file.$id}`;

        const img = document.createElement('img');
        img.src = storage.getFilePreview({
            bucketId: '[BUCKET_ID]',
            fileId: file.$id,
            width: 200,
            height: 200,
        }).toString();
        img.alt = file.name;

        const label = document.createElement('span');
        label.textContent = `${file.name} (${(file.sizeOriginal / 1024).toFixed(1)} KB)`;

        preview.appendChild(img);
        preview.appendChild(label);
        gallery.appendChild(preview);
    }
}

function handleFileUpdated(file: Record<string, any>) {
    const label = document.querySelector(`#file-${file.$id} span`);
    if (label) {
        label.textContent = `${file.name} (${(file.sizeOriginal / 1024).toFixed(1)} KB)`;
    }
}

function handleFileDeleted(file: Record<string, any>) {
    const preview = document.getElementById(`file-${file.$id}`);
    if (preview) {
        preview.remove();
    }
}

// --- Cleanup when no longer needed (e.g., component unmount) ---
// unsubscribe();
```

**Key points:**

- **Single `subscribe` call** with an array of two channels handles both row changes and file uploads through one WebSocket connection.
- **Event routing** uses `events.some()` to check the event strings — `.rows.` vs `.files.` distinguishes the resource type, and the `.create` / `.update` / `.delete` suffix identifies the action.
- The `response` object provides `events` (array of matched event strings), `payload` (the affected resource with all its fields), `channels` (which subscribed channels matched), and `timestamp` (ISO 8601).
- Call `unsubscribe()` to close the subscription when you no longer need it (e.g., on component unmount in React/Vue/Svelte).

